    private String convertStoreTimeFormat(String origin) {
        if (origin.length() == 0) return "";

        String hour = origin.substring(0, 2);
        String mins = origin.substring(2);

        int encoderHr = Encoder.parseInt(hour);
        int encoderMin = Encoder.parseInt(mins);
        if (encoderHr > 23) {
            encoderHr -= 24;

            if (encoderMin > 45 || encoderMin == 0) {
                encoderMin = 0;
                encoderHr++;
            } else if (encoderMin <= 15) {
                encoderMin = 15;
            } else if (encoderMin <= 30) {
                encoderMin = 30;
            } else if (encoderMin <= 45) {
                encoderMin = 45;
            }
        }

        return (encoderHr <= 9 ? "0" + encoderHr : encoderHr) + ":" + (encoderMin == 0 ? "00" : encoderMin);
    }

